import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { supabase } from '../supabaseClient';

function Products() {
  const [products, setProducts] = useState([]);
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('products')
        .select('*')
        .order('id', { ascending: false });
      
      if (error) {
        console.error('Error fetching products:', error);
        // fallback ke localStorage jika Supabase error
        const stored = localStorage.getItem('products');
        if (stored) setProducts(JSON.parse(stored));
      } else {
        setProducts(data || []);
        localStorage.setItem('products', JSON.stringify(data || []));
      }
    } catch (error) {
      console.error('Error:', error);
      // fallback ke localStorage
      const stored = localStorage.getItem('products');
      if (stored) setProducts(JSON.parse(stored));
    } finally {
      setLoading(false);
    }
  };

  const addProduct = async () => {
    if (name && price) {
      setLoading(true);
      try {
        if (editingId) {
          // update existing
          const { error } = await supabase
            .from('products')
            .update({ name, price: parseFloat(price) })
            .eq('id', editingId);
          
          if (error) throw error;
          setEditingId(null);
          alert('Produk berhasil diupdate!');
        } else {
          // add new
          const { error } = await supabase
            .from('products')
            .insert([{ name, price: parseFloat(price) }]);
          
          if (error) throw error;
          alert('Produk berhasil ditambahkan!');
        }
        setName('');
        setPrice('');
        fetchProducts();
      } catch (error) {
        console.error('Error:', error);
        alert('Error: ' + error.message);
      } finally {
        setLoading(false);
      }
    }
  };

  const startEdit = (product) => {
    setEditingId(product.id);
    setName(product.name);
    setPrice(product.price.toString());
  };

  const deleteProduct = async (id) => {
    if (window.confirm('Hapus produk ini?')) {
      setLoading(true);
      try {
        const { error } = await supabase
          .from('products')
          .delete()
          .eq('id', id);
        
        if (error) throw error;
        fetchProducts();
      } catch (error) {
        console.error('Error:', error);
        alert('Error: ' + error.message);
      } finally {
        setLoading(false);
      }
    }
  };

  return (
    <div>
      <Link className="btn btn-secondary mb-3" to="/">Kembali ke Home</Link>
      <h2>Harga Produk per Box/Pcs</h2>
      <div className="card mb-4">
        <div className="card-body">
          <div className="mb-3">
            <input type="text" className="form-control" placeholder="Nama Produk" value={name} onChange={e => setName(e.target.value)} disabled={loading} />
            <input type="number" className="form-control mt-2" placeholder="Harga per Box/Pcs" value={price} onChange={e => setPrice(e.target.value)} disabled={loading} />
            <button className="btn btn-primary mt-3" onClick={addProduct} disabled={loading}>{editingId ? 'Update Produk' : 'Tambah Produk'}</button>
          </div>
        </div>
      </div>
      <table className="table table-striped">
        <thead>
          <tr>
            <th>Nama</th>
            <th>Harga per Box/Pcs</th>
            <th>Aksi</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id}>
              <td>{p.name}</td>
              <td>Rp {p.price.toLocaleString()}</td>
              <td>
                <button className="btn btn-info btn-sm me-2" onClick={() => startEdit(p)} disabled={loading}>Edit</button>
                <button className="btn btn-danger btn-sm" onClick={() => deleteProduct(p.id)} disabled={loading}>Hapus</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Products;